import{_ as t,a,b as o,c as d,d as p,e as r}from"./chunks/查询额度成功.BKueuYqe.js";import{_ as s,o as n,c as l,a2 as i}from"./chunks/framework.DnrXFDHb.js";const y=JSON.parse('{"title":"Dropbox Channel যোগ করা","description":"","frontmatter":{},"headers":[],"relativePath":"bn-BD/upload/dropbox.md","filePath":"bn-BD/upload/dropbox.md","lastUpdated":1781962217000}'),c={name:"bn-BD/upload/dropbox.md"};function h(b,e,u,m,f,g){return n(),l("div",null,[...e[0]||(e[0]=[i('<h1 id="dropbox-channel-যোগ-করা" tabindex="-1">Dropbox Channel যোগ করা <a class="header-anchor" href="#dropbox-channel-যোগ-করা" aria-label="Permalink to &quot;Dropbox Channel যোগ করা&quot;">​</a></h1><h2 id="আগে-যা-লাগবে" tabindex="-1">আগে যা লাগবে <a class="header-anchor" href="#আগে-যা-লাগবে" aria-label="Permalink to &quot;আগে যা লাগবে&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Requirement</th><th>কেন লাগবে</th></tr></thead><tbody><tr><td>Dropbox account</td><td>Sign in এবং app authorize করতে লাগে</td></tr><tr><td>Dropbox app</td><td><code>App Key</code> এবং <code>App Secret</code> generate করতে লাগে</td></tr><tr><td>আপনার ImgBed domain</td><td>OAuth redirect URI-এর জন্য লাগে</td></tr><tr><td>Available Dropbox storage</td><td>Actual file storage location হিসেবে ব্যবহৃত হবে</td></tr></tbody></table><h2 id="setup-steps" tabindex="-1">Setup Steps <a class="header-anchor" href="#setup-steps" aria-label="Permalink to &quot;Setup Steps&quot;">​</a></h2><h3 id="step-1-dropbox-app-তৈরি-করুন" tabindex="-1">Step 1: Dropbox App তৈরি করুন <a class="header-anchor" href="#step-1-dropbox-app-তৈরি-করুন" aria-label="Permalink to &quot;Step 1: Dropbox App তৈরি করুন&quot;">​</a></h3><ol><li>Dropbox App Console খুলুন:</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://www.dropbox.com/developers/apps</span></span></code></pre></div><ol start="2"><li>নতুন app তৈরি করুন।</li><li>Access type হিসেবে নির্বাচন করুন:</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>App folder</span></span></code></pre></div><ol start="4"><li>App-এর চেনা যায় এমন নাম দিন, যেমন <code>imgbed-app</code>।</li><li>App তৈরি হলে app details page খুলুন।</li></ol><p>Recommended access type:</p><table tabindex="0"><thead><tr><th>Access Type</th><th>Recommendation</th></tr></thead><tbody><tr><td><code>App folder</code></td><td>Recommended। ImgBed যেভাবে files store করে তার সঙ্গে match করে।</td></tr><tr><td><code>Full Dropbox</code></td><td>Recommended নয়। ImgBed-এর full-account access দরকার নেই।</td></tr></tbody></table><p><img src="'+t+'" alt="Create Dropbox app" loading="lazy"></p><h3 id="step-2-redirect-uri-যোগ-করুন" tabindex="-1">Step 2: Redirect URI যোগ করুন <a class="header-anchor" href="#step-2-redirect-uri-যোগ-করুন" aria-label="Permalink to &quot;Step 2: Redirect URI যোগ করুন&quot;">​</a></h3><p>Dropbox app details page-এ OAuth বা Redirect URI settings খুঁজে যোগ করুন:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://your-domain.com/api/oauth/dropbox/callback</span></span></code></pre></div><p>একাধিক domain থেকে admin panel ব্যবহার করলে প্রতিটি matching callback URL যোগ করুন।</p><p><img src="'+a+'" alt="Configure redirect URI" loading="lazy"></p><h3 id="step-3-app-permissions-configure-করুন" tabindex="-1">Step 3: App Permissions Configure করুন <a class="header-anchor" href="#step-3-app-permissions-configure-করুন" aria-label="Permalink to &quot;Step 3: App Permissions Configure করুন&quot;">​</a></h3><p><code>Permissions</code> tab খুলে অন্তত এই scopes enable করুন:</p><table tabindex="0"><thead><tr><th>Scope</th><th>Required</th><th>Purpose</th></tr></thead><tbody><tr><td><code>account_info.read</code></td><td>Required</td><td>Account এবং quota information পড়ে</td></tr><tr><td><code>files.metadata.read</code></td><td>Required</td><td>Path checks-এর জন্য file এবং folder metadata পড়ে</td></tr><tr><td><code>files.metadata.write</code></td><td>Required</td><td>Folders create এবং metadata write করে</td></tr><tr><td><code>files.content.write</code></td><td>Required</td><td>Files upload করে। এই scope না থাকলে <code>required scope &#39;files.content.write&#39;</code> error হয়।</td></tr><tr><td><code>files.content.read</code></td><td>Recommended</td><td>Download, preview এবং temporary file links allow করে</td></tr></tbody></table><p>Scopes নির্বাচন করার পর page-এর bottom-এ <code>Submit</code> ক্লিক করুন।</p><p><img src="'+o+'" alt="Add permissions" loading="lazy"></p><p>Important:</p><table tabindex="0"><thead><tr><th>Situation</th><th>কী করবেন</th></tr></thead><tbody><tr><td>Scopes বদলেছেন</td><td>Token authorization flow আবার চালিয়ে নতুন <code>Refresh Token</code> নিন।</td></tr><tr><td>Reauthorize করেননি</td><td>Old token নতুন permissions পাবে না, তাই uploads এখনও fail করতে পারে।</td></tr></tbody></table><h3 id="step-4-app-credentials-copy-করুন" tabindex="-1">Step 4: App Credentials Copy করুন <a class="header-anchor" href="#step-4-app-credentials-copy-করুন" aria-label="Permalink to &quot;Step 4: App Credentials Copy করুন&quot;">​</a></h3><p>Dropbox app page থেকে এই দুটো value save করুন:</p><table tabindex="0"><thead><tr><th>Dropbox Field</th><th>ImgBed Field</th></tr></thead><tbody><tr><td><code>App key</code></td><td><code>App Key</code></td></tr><tr><td><code>App secret</code></td><td><code>App Secret</code></td></tr></tbody></table><h3 id="step-5-dropbox-channel-পূরণ-করুন" tabindex="-1">Step 5: Dropbox Channel পূরণ করুন <a class="header-anchor" href="#step-5-dropbox-channel-পূরণ-করুন" aria-label="Permalink to &quot;Step 5: Dropbox Channel পূরণ করুন&quot;">​</a></h3><p>Upload Settings-এ <code>Dropbox</code> নির্বাচন করে পূরণ করুন:</p><table tabindex="0"><thead><tr><th>ImgBed Field</th><th>কী দেবেন</th></tr></thead><tbody><tr><td>Channel name</td><td>চেনা যায় এমন নাম, যেমন <code>Main Dropbox</code></td></tr><tr><td>App Key</td><td>Dropbox <code>App key</code></td></tr><tr><td>App Secret</td><td>Dropbox <code>App secret</code></td></tr><tr><td>Refresh Token</td><td>আপাতত empty রাখুন</td></tr><tr><td>Root directory</td><td>Optional। Default <code>imgbed</code>।</td></tr><tr><td>Note</td><td>Optional</td></tr></tbody></table><p><img src="'+d+'" alt="Get token" loading="lazy"></p><h3 id="step-6-refresh-token-নিন" tabindex="-1">Step 6: Refresh Token নিন <a class="header-anchor" href="#step-6-refresh-token-নিন" aria-label="Permalink to &quot;Step 6: Refresh Token নিন&quot;">​</a></h3><ol><li>ImgBed-এ <code>Get Token</code> ক্লিক করুন।</li><li>যে Dropbox account connect করতে চান সেটিতে sign in করুন।</li><li>Authorization prompt approve করুন।</li><li>Callback page একটি <code>Refresh Token</code> দেখাবে।</li><li>সেটি copy করুন।</li><li>ImgBed-এ ফিরে <code>Refresh Token</code> field-এ paste করুন।</li></ol><p><img src="'+p+'" alt="Copy token" loading="lazy"></p><h2 id="কীভাবে-যাচাই-করবেন" tabindex="-1">কীভাবে যাচাই করবেন <a class="header-anchor" href="#কীভাবে-যাচাই-করবেন" aria-label="Permalink to &quot;কীভাবে যাচাই করবেন&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Check</th><th>Expected Result</th></tr></thead><tbody><tr><td>Channel card</td><td>Save করার পর Dropbox channel দেখা যায়।</td></tr><tr><td>Channel switch</td><td>Channel enable করা যায়।</td></tr><tr><td>Token saved</td><td>Detail page-এ <code>Refresh Token</code> save হয়েছে দেখা যায়।</td></tr><tr><td>Upload test</td><td>Test image Dropbox app folder-এ দেখা যায়।</td></tr></tbody></table><p>Quota limits enabled থাকলে quota query ক্লিক করুন। Successful query-এর পর channel card used space, total space এবং last update time দেখায়।</p><p><img src="'+r+`" alt="Quota query success" loading="lazy"></p><h2 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to &quot;Troubleshooting&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Problem</th><th>Fix</th></tr></thead><tbody><tr><td>ImgBed configuration incomplete বলছে</td><td><code>App Key</code>, <code>App Secret</code> এবং <code>Refresh Token</code> সব পূরণ করা আছে কি না check করুন।</td></tr><tr><td>Authorization successful কিন্তু <code>Refresh Token</code> দেখাচ্ছে না</td><td>আবার <code>Get Token</code> ক্লিক করুন এবং offline authorization flow ব্যবহার হচ্ছে কি না নিশ্চিত করুন।</td></tr><tr><td>Upload <code>required scope &#39;files.content.write&#39;</code> দিয়ে fail করছে</td><td><code>files.content.write</code> enable করুন, <code>Submit</code> ক্লিক করুন, তারপর নতুন <code>Refresh Token</code> নিন।</td></tr><tr><td>Callback fail করছে</td><td>Redirect URI <code>https://your-domain.com/api/oauth/dropbox/callback</code> কি না confirm করুন।</td></tr><tr><td>Files খুঁজে পাওয়া যাচ্ছে না</td><td>Dropbox app <code>App folder</code> mode-এ তৈরি হয়েছে কি না confirm করুন।</td></tr></tbody></table><h2 id="quick-flow" tabindex="-1">Quick Flow <a class="header-anchor" href="#quick-flow" aria-label="Permalink to &quot;Quick Flow&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Dropbox App Console খুলুন</span></span>
<span class="line"><span>-&gt; App তৈরি করুন</span></span>
<span class="line"><span>-&gt; App folder access নির্বাচন করুন</span></span>
<span class="line"><span>-&gt; https://your-domain.com/api/oauth/dropbox/callback যোগ করুন</span></span>
<span class="line"><span>-&gt; account_info.read / files.metadata.read / files.metadata.write / files.content.write enable করুন</span></span>
<span class="line"><span>-&gt; চাইলে files.content.read enable করুন</span></span>
<span class="line"><span>-&gt; Submit ক্লিক করুন</span></span>
<span class="line"><span>-&gt; App Key এবং App Secret copy করুন</span></span>
<span class="line"><span>-&gt; ImgBed-এ পূরণ করুন</span></span>
<span class="line"><span>-&gt; Get Token ক্লিক করুন</span></span>
<span class="line"><span>-&gt; Callback page থেকে Refresh Token copy করুন</span></span>
<span class="line"><span>-&gt; ImgBed-এ paste করে save করুন</span></span></code></pre></div><h2 id="references" tabindex="-1">References <a class="header-anchor" href="#references" aria-label="Permalink to &quot;References&quot;">​</a></h2><ol><li>Dropbox App Console: <a href="https://www.dropbox.com/developers/apps" target="_blank" rel="noreferrer">https://www.dropbox.com/developers/apps</a></li><li>Dropbox OAuth Guide: <a href="https://developers.dropbox.com/oauth-guide" target="_blank" rel="noreferrer">https://developers.dropbox.com/oauth-guide</a></li><li>Dropbox Developer Guide: <a href="https://www.dropbox.com/developers/reference/developer-guide" target="_blank" rel="noreferrer">https://www.dropbox.com/developers/reference/developer-guide</a></li></ol>`,45)])])}const A=s(c,[["render",h]]);export{y as __pageData,A as default};
